content:
:before {
    content: '';
    position: absolute;
    top: -200px; right: -200px;
    width: 500px; height: 500px;
    background: radial-gradient(circle, rgba(59, 130, 246, 0.08) 0%, transparent 70%);
    border-radius: 50%;
    pointer-events: none;
  }
  .slide-number {
    position: absolute; bottom: 48px; right: 72px;
    font-size: 16px; font-weight: 600; color: var(--text-muted); letter-spacing: 2px;
  }
  .author-tag {
    position: absolute; bottom: 48px; left: 72px;
    font-size: 15px; font-weight: 500; color: var(--text-muted);
  }
  .slide-label {
    font-size: 15px; font-weight: 700; letter-spacing: 3px;
    text-transform: uppercase; color: var(--accent-blue); margin-bottom: 24px;
  }
  .slide-title {
    font-size: 52px; font-weight: 800; line-height: 1.15;
    margin-bottom: 32px; letter-spacing: -1px;
  }
  .slide-subtitle {
    font-size: 24px; font-weight: 500; line-height: 1.5;
    color: var(--text-secondary); margin-bottom: 40px;
  }

  .highlight { color: var(--accent-blue); }
  .highlight-green { color: var(--accent-green); }
  .highlight-amber { color: var(--accent-amber); }
  .highlight-red { color: var(--accent-red); }
  .highlight-cyan { color: var(--accent-cyan); }
  .highlight-purple { color: var(--accent-purple); }

  .card {
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: 16px; padding: 32px; margin-bottom: 20px;
  }
  .terminal {
    background: #0d1117; border: 1px solid #30363d; border-radius: 12px;
    padding: 24px; font-family: 'JetBrains Mono', monospace;
    font-size: 16px; line-height: 1.8; margin: 16px 0;
  }
  .terminal .prompt { color: var(--accent-green); }
  .terminal .cmd { color: var(--text-primary); }
  .terminal .output { color: var(--text-secondary); }
  .terminal .highlight-val { color: var(--accent-amber); }
  .terminal .comment { color: var(--text-muted); }
